/*Table structure for table `product_reviews` */

DROP TABLE IF EXISTS `product_reviews`;

CREATE TABLE `product_reviews` (
  `review_id` int(11) NOT NULL AUTO_INCREMENT,
  `product_id` int(11) NOT NULL,
  `buyer_id` int(11) NOT NULL,
  `order_id` int(11) NOT NULL,
  `rating` int(11) NOT NULL CHECK (`rating` >= 1 and `rating` <= 5),
  `review_text` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`review_id`),
  KEY `order_id` (`order_id`),
  KEY `idx_product_id` (`product_id`),
  KEY `idx_buyer_id` (`buyer_id`),
  CONSTRAINT `product_reviews_ibfk_1` FOREIGN KEY (`product_id`) REFERENCES `products` (`product_id`) ON DELETE CASCADE,
  CONSTRAINT `product_reviews_ibfk_2` FOREIGN KEY (`buyer_id`) REFERENCES `buyers` (`buyer_id`) ON DELETE CASCADE,
  CONSTRAINT `product_reviews_ibfk_3` FOREIGN KEY (`order_id`) REFERENCES `orders` (`order_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=250 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Data for the table `product_reviews` */

insert  into `product_reviews`(`review_id`,`product_id`,`buyer_id`,`order_id`,`rating`,`review_text`,`created_at`) values (2,42,8,1,5,'Nice Product!!!','2025-03-01 14:15:56'),(3,41,8,1,5,'Super Beautiful!!!!','2025-03-01 14:15:56'),(6,100,100,200,5,'The Ascension Maxi is an absolute dream. The organic cotton breathes beautifully, and the puffy sleeves add a level of drama that feels both vintage and modern. Truly a refined piece.','2025-09-19 14:15:56'),(7,105,100,200,5,'I needed a staple for my professional wardrobe, and this skirt delivers. The organic wool feels incredibly luxurious against the skin, and the cut is sharp and empowering.','2025-09-18 14:15:56'),(8,104,101,201,5,'Structured perfection. The bamboo fabric is surprisingly soft yet holds its architectural shape wonderfully. It makes me feel like a leader every time I wear it.','2025-09-01 14:15:56'),(9,109,101,201,4,'I love the sustainability angle of the cork leather—it is edgy, chic, and feels very high-end. My only note is that it runs slightly small, but the texture is divine.','2025-09-06 14:15:56'),(10,100,101,300,5,'Absolutely exquisite! The The Ascension Maxi Dress exceeded my expectations.','2025-04-08 14:15:56'),(11,100,102,301,4,'Beautiful and elegant, though it shipping took a while.','2025-05-18 14:15:56'),(12,100,103,302,5,'Finally, luxury that feels good. This piece is timeless and sustainable.','2025-02-01 14:15:56'),(13,100,104,303,5,'The The Ascension Maxi Dress is simply divine. Highly recommend for any occasion.','2025-05-31 14:15:56'),(14,101,100,304,5,'A refined addition to my wardrobe. The craftsmanship is impeccable.','2025-10-28 14:15:56'),(15,101,102,305,4,'I love the Gaia Wrap Gown, very breathable. Just be careful with sizing.','2025-12-01 14:15:56'),(16,101,103,306,5,'Absolutely flattering! The Gaia Wrap Gown exceeded my expectations.','2025-04-06 14:15:56'),(17,101,104,307,4,'Great quality and chic texture. A staple piece.','2025-08-21 14:15:56'),(18,102,100,308,3,'The Set