/*Table structure for table `products` */

DROP TABLE IF EXISTS `products`;

CREATE TABLE `products` (
  `product_id` int(11) NOT NULL AUTO_INCREMENT,
  `seller_id` int(11) NOT NULL,
  `product_name` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `materials` text DEFAULT NULL,
  `SDG` enum('handmade','biodegradable','both') DEFAULT NULL,
  `price` decimal(10,2) NOT NULL,
  `category` varchar(100) NOT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `views_count` int(11) DEFAULT 0,
  `rating` decimal(3,2) DEFAULT 0.00,
  `total_reviews` int(11) DEFAULT 0,
  `total_sold` int(11) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`product_id`),
  KEY `idx_seller_id` (`seller_id`),
  KEY `idx_category` (`category`),
  KEY `idx_product_name` (`product_name`),
  CONSTRAINT `products_ibfk_1` FOREIGN KEY (`seller_id`) REFERENCES `sellers` (`seller_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=160 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Data for the table `products` */

insert  into `products`(`product_id`,`seller_id`,`product_name`,`description`,`materials`,`SDG`,`price`,`category`,`is_active`,`views_count`,`rating`,`total_reviews`,`total_sold`,`created_at`,`updated_at`) values (41,7,'Summer Overshirt','The Summer Overshirt With Vintage Swiss Embroidery','100% cotton','both','500.00','tops',1,60,'5.00',2,5,'2025-01-03 14:15:56','2025-12-01 16:19:59'),(42,7,'Blouson Top','Our Style No. ATTIF-WS142\r\n\r\nManufacturer Style No. 250WCB0088 - DDD088SS - 024\r\n\r\nModel is wearing size 38. View detailed measurements of this item.\r\n','potek ihhiihihsdOur Style No. ATTIF-WS142\r\n\r\nManufacturer Style No. 250WCB0088 - DDD088SS - 024\r\n\r\nModel is wearing size 38. View detailed measurements of this item.\r\nSAD\r\nDSADASD\r\n','both','3423435.00','tops',1,75,'5.00',2,108,'2024-12-31 14:15:56','2025-12-01 16:18:52'),(100,100,'The Ascension Maxi Dress','New for the season, the Ascension Maxi captures ethereal elegance. Its signature puffy-sleeve design introduces romantic volume, while the sophisticated front button loop closure makes this piece a distinct icon of refined femininity.','Organic Cotton','biodegradable','12500.00','dresses',1,3,'4.80',5,5,'2025-01-11 14:15:56','2025-12-03 07:01:24'),(101,101,'Gaia Wrap Gown','Exuding bohemian glamour, this flowing silhouette defines visual identity through chic ruffle trims. This iconic piece embodies the house\'s flair for sensual, yet sophisticated, luxury.','Peace Silk','both','14200.00','Dresses',1,0,'4.50',4,4,'2025-02-27 14:15:56','2025-12-01 16:18:52'),(102,102,'Seta Evening Slip','A minimalist masterpiece. This slip dress features delicate spaghetti straps and a bias cut that drapes effortlessly against the body, elevating your evening wardrobe with understated luxury.','Tencel™ Lyocell','handmade','8500.00','dresses',1,2,'4.25',4,4,'2025-04-28 14:15:56','2025-12-03 06:24:17'),(103,103,'Ethereal Garden Midi','Inspired by botanical forms, this midi dress features hand-embroidered floral motifs. The billow sleeves and cinched waist create a timeless silhouette suitable for high-society garden parties.','Ramie','both','11000.00','Dresses',1,1,'4.25',4,4,'2024-12-16 14:15:56','2025-12-01 16:18:52'),(104,104,'Muse Structure Dress','Architectural lines meet sustainable luxury. This structured piece offers a powerful silhouette for the modern leader, featuring a sharp neckline and asymmetrical hem.','Bamboo Fabric','biodegradable','9800.00','Dresses',0,0,'4.40',5,5,'2025-02-09 14:15:56','2025-12-03 08:13:19'),(105,100,'Velare Pencil Skirt','Refined and sharp, this pencil skirt is a wardrobe staple. Crafted with precision, it offers a sleek profile that transitions seamlessly from the boardroom to evening engagements.','Organic Wool','biodegradable','5500.00','Skirts',0,0,'4.60',5,5,'2024-11-28 14:15:56','2025-12-03 08:02:38'),(106,101,'Boheme Tiered Skirt','Layers of sustainable fabric cascade to create movement and grace. This tiered skirt pairs perfectly with a fitted blouse for a look of effortless chic.','EcoVero™ Viscose','both','6200.00','Skirts',1,3,'4.25',4,4,'2024-12-22 14:15:56','2025-12-01 16:19:43'),(107,102,'Stone Wash Midi','Featuring a unique texture derived from natural mineral dyes, this midi skirt offers a tactile experience. The high-waisted cut elongates the figure.','Hemp Fiber','biodegradable','4800.00','skirts',1,0,'4.25',4,4,'2024-11-21 14:15:56','2025-12-03 06:39:28'),(108,103,'Silk Breeze Wrap','An adjustable wrap skirt that flows with every step. The luxurious sheen of the fabric adds an element of opulence to a casual silhouette.','Peace Silk','handmade','7500.00','Skirts',1,3,'4.75',4,4,'2024-12-04 14:15:56','2025-12-01 16:18:52'),(109,104,'Urban Cork Mini','Bold and edgy, this mini skirt utilizes sustainable cork leather. It features metallic hardware details that contrast with the natural texture of the material.','Cork Leather','both','4500.00','skirts',1,1,'4.20',5,5,'2025-04-20 14:15:56','2025-12-03 08:08:18'),(11