'2025-12-03 08:13:41'),(155,100,'Velare Tote','A spacious tote bag for the daily commute. Made from durable abaca fiber, it is both strong and stylish.','Abacá Fiber','biodegradable','5500.00','Accessories',0,0,'4.75',4,4,'2024-11-24 14:15:56','2025-12-03 08:02:25'),(156,101,'Gaia Silk Scarf','A printed silk scarf that can be worn around the neck, in the hair, or tied to a bag. Features hand-rolled edges.','Peace Silk','handmade','3200.00','Accessories',1,0,'4.25',4,4,'2024-11-17 14:15:56','2025-12-01 16:18:52'),(157,102,'Seta Belt','A wide belt designed to cinch coats and dresses. Made from cork leather with a recycled brass buckle.','Cork Leather','biodegradable','2500.00','accessories',1,1,'4.50',4,4,'2025-05-08 14:15:56','2025-12-03 06:16:49'),(158,103,'Woven Hat','A wide-brimmed hat made from natural ramie fibers. Perfect for sun protection with a touch of glamour.','Ramie','biodegradable','2800.00','Accessories',1,0,'4.75',4,4,'2024-12-19 14:15:56','2025-12-01 16:18:52'),(159,104,'Clutch Bag','A structured clutch made from upcycled fabric blends. Features a detachable chain strap for versatility.','Upcycled Fabric Blends','both','4200.00','Accessories',0,0,'4.50',4,4,'2025-01-14 14:15:56','2025-12-03 08:13:32');

/*Table structure for table `review_images` */

DROP TABLE IF EXISTS `review_images`;

CREATE TABLE `review_images` (
  `review_image_id` int(11) NOT NULL AUTO_INCREMENT,
  `review_id` int(11) NOT NULL,
  `image_url` varchar(255) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`review_image_id`),
  KEY `idx_review_id` (`review_id`),
  CONSTRAINT `review_images_ibfk_1` FOREIGN KEY (`review_id`) REFERENCES `product_reviews` (`review_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

/*Data for the table `review_images` */

/*Table structure for table `rider_withdrawals` */

DROP TABLE IF EXISTS `rider_withdrawals`;

CREATE TABLE `rider_withdrawals` (
  `withdrawal_id` int(11) NOT NULL AUTO_INCREMENT,
  `rider_id` int(11) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `withdrawal_method` varchar(50) DEFAULT 'Cash',
  `status` enum('pending','completed','rejected','cancelled') DEFAULT 'pending',
  `requested_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `processed_at` timestamp NULL DEFAULT NULL,
  `notes` text DEFAULT NULL,
  PRIMARY KEY (`withdrawal_id`),
  KEY `idx_rider_id` (`rider_id`),
  KEY `idx_status` (`status`),
  KEY `idx_requested_at` (`requested_at`),
  CONSTRAINT `rider_withdrawals_ibfk_1` FOREIGN KEY (`rider_id`) REFERENCES `riders` (`rider_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

/*Data for the table `rider_withdrawals` */

insert  into `rider_withdrawals`(`withdrawal_id`,`rider_id`,`amount`,`withdrawal_method`,`status`,`requested_at`,`processed_at`,`notes`) values (1,4,'100.00','Bank Transfer','completed','2025-11-23 04:08:13','2025-11-23 06:02:46',''),(10,4,'100.00','GCash','rejected','2025-11-23 09:09:09','2025-11-23 09:10:06','\nRejection reason: '),(11,4,'100.00','Bank Transfer','rejected','2025-11-23 09:11:15','2025-11-23 09:11:34','\nRejection reason: '),(12,100,'1500.00','Cash','completed','2025-12-01 16:04:36','2025-12-01 16:05:49','Need Cash ASAP');

/*Table structure for table `riders` */

DROP TABLE IF EXISTS `riders`;

CREATE TABLE `riders` (
  `rider_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `first_name` varchar(100) NOT NULL,
  `last_name` varchar(100) NOT NULL,
  `phone_number` varchar(20) NOT NULL,
  `profile_image` varchar(255) DEFAULT NULL,
  `vehicle_type` varchar(50) DEFAULT NULL,
  `id_type` varchar(50) DEFAULT NULL,
  `id_file_path` varchar(255) DEFAULT NULL,
  `rating` decimal(3,2) DEFAULT 0.00,
  `total_earnings` decimal(10,2) DEFAULT 0.00,
  `status` enum('available','busy','offline') DEFAULT 'offline',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `orcr_file_path` varchar(255) DEFAULT NULL,
  `driver_license_file_path` varchar(255) DEFAULT NULL,
  `plate_number` varchar(10) DEFAULT NULL,
  `available_balance` decimal(10,2) DEFAULT 0.00 COMMENT 'Available balance for withdrawal',
  `account_status` varchar(20) DEFAULT 'active',
  `suspension_end` datetime DEFAULT NULL,
  `suspension_reason` text DEFAULT NULL,
  `report_count` int(11) DEFAULT 0,
  PRIMARY KEY (`rider_id`),
  UNIQUE KEY `user_id` (`user_id`),
  KEY `idx_status` (`status`),
  KEY `idx_riders_account_status` (`account_status`),
  CONSTRAINT `riders_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=105 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

