/*Table structure for table `seller_vouchers` */

DROP TABLE IF EXISTS `seller_vouchers`;

CREATE TABLE `seller_vouchers` (
  `seller_voucher_id` int(11) NOT NULL AUTO_INCREMENT,
  `seller_id` int(11) NOT NULL,
  `voucher_id` int(11) NOT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `selected_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`seller_voucher_id`),
  UNIQUE KEY `unique_seller_voucher` (`seller_id`,`voucher_id`),
  KEY `idx_seller_vouchers_seller_id` (`seller_id`),
  KEY `idx_seller_vouchers_voucher_id` (`voucher_id`),
  KEY `idx_seller_vouchers_active` (`is_active`),
  CONSTRAINT `seller_vouchers_ibfk_1` FOREIGN KEY (`seller_id`) REFERENCES `sellers` (`seller_id`) ON DELETE CASCADE,
  CONSTRAINT `seller_vouchers_ibfk_2` FOREIGN KEY (`voucher_id`) REFERENCES `vouchers` (`voucher_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

