/*Table structure for table `sellers` */

DROP TABLE IF EXISTS `sellers`;

CREATE TABLE `sellers` (
  `seller_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `first_name` varchar(100) DEFAULT NULL,
  `last_name` varchar(100) DEFAULT NULL,
  `shop_name` varchar(255) NOT NULL,
  `shop_description` text DEFAULT NULL,
  `shop_logo` varchar(255) DEFAULT NULL,
  `phone_number` varchar(20) DEFAULT NULL,
  `id_type` varchar(50) DEFAULT NULL,
  `rating` decimal(3,2) DEFAULT 0.00,
  `total_sales` decimal(12,2) DEFAULT 0.00,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `id_file_path` varchar(255) DEFAULT NULL,
  `business_permit_file_path` varchar(255) DEFAULT NULL,
  `account_status` varchar(20) DEFAULT 'active',
  `suspension_end` datetime DEFAULT NULL,
  `suspension_reason` text DEFAULT NULL,
  `report_count` int(11) DEFAULT 0,
  PRIMARY KEY (`seller_id`),
  UNIQUE KEY `user_id` (`user_id`),
  KEY `idx_shop_name` (`shop_name`),
  KEY `idx_sellers_account_status` (`account_status`),
  CONSTRAINT `sellers_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=105 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

