/* Trigger structure for table `product_reviews` */

DELIMITER $$

/*!50003 DROP TRIGGER*//*!50032 IF EXISTS */ /*!50003 `update_product_rating_after_review` */$$

/*!50003 CREATE */ /*!50017 DEFINER = 'root'@'localhost' */ /*!50003 TRIGGER `update_product_rating_after_review` AFTER INSERT ON `product_reviews` FOR EACH ROW BEGIN
    UPDATE products p
    SET 
        rating = (SELECT AVG(rating) FROM product_reviews WHERE product_id = NEW.product_id),
        total_reviews = (SELECT COUNT(*) FROM product_reviews WHERE product_id = NEW.product_id)
    WHERE product_id = NEW.product_id;
END */$$


DELIMITER ;

/* Trigger structure for table `product_reviews` */

DELIMITER $$

/*!50003 DROP TRIGGER*//*!50032 IF EXISTS */ /*!50003 `update_seller_rating_after_review` */$$

/*!50003 CREATE */ /*!50017 DEFINER = 'root'@'localhost' */ /*!50003 TRIGGER `update_seller_rating_after_review` AFTER INSERT ON `product_reviews` FOR EACH ROW BEGIN
    UPDATE sellers s
    SET rating = (
        SELECT AVG(pr.rating) 
        FROM product_reviews pr
        JOIN products p ON pr.product_id = p.product_id
        WHERE p.seller_id = (SELECT seller_id FROM products WHERE product_id = NEW.product_id)
    )
    WHERE seller_id = (SELECT seller_id FROM products WHERE product_id = NEW.product_id);
END */$$


DELIMITER ;

